+            TextField("Search skills", text: self.$searchQuery)
+                .textFieldStyle(.roundedBorder)
+                .frame(maxWidth: 320)
+            Picker("Filter", selection: self.$filter) {
+                ForEach(SkillsFilter.allCases) { filter in
+                    Text(filter.title)
